function Background({ children }: { children: React.ReactNode }) {
  const stars = useMemo(() => Array.from({ length: 24 }, (_, i) => ({
    x: `${(i * 7.3 + 4) % 96}%`,
    y: `${(i * 11.7 + 5) % 92}%`,
    size: 1 + (i % 3),
    dur: `${2 + (i % 5) * 0.8}s`,
    delay: `${(i * 0.4) % 4}s`,
    color: i % 4 === 0 ? 'rgba(0,146,214,0.7)' : i % 4 === 1 ? 'rgba(139,92,246,0.6)' : i % 4 === 2 ? 'rgba(0,200,180,0.6)' : 'rgba(255,255,255,0.5)',
  })), [])
  return (
    <div style={{minHeight:'100vh',background:'#070711',position:'relative',overflow:'hidden',display:'flex',alignItems:'center',justifyContent:'center'}}>
      <div style={{position:'absolute',inset:0,overflow:'hidden',pointerEvents:'none'}}>
        <div style={{position:'absolute',width:'140%',height:'35%',top:'5%',left:'-20%',background:'linear-gradient(90deg,transparent 0%,rgba(0,146,214,.07) 20%,rgba(90,46,145,.05) 40%,rgba(0,200,180,.06) 60%,rgba(0,146,214,.08) 80%,transparent 100%)',filter:'blur(50px)',animation:'auroraSlide 18s ease-in-out infinite'}} />
        <div style={{position:'absolute',width:'130%',height:'25%',top:'55%',left:'-15%',background:'linear-gradient(90deg,transparent 0%,rgba(90,46,145,.05) 25%,rgba(0,200,180,.04) 50%,rgba(139,92,246,.06) 75%,transparent 100%)',filter:'blur(45px)',animation:'auroraSlide2 22s ease-in-out infinite'}} />
      </div>
      <div style={{position:'absolute',inset:0,pointerEvents:'none',backgroundImage:'radial-gradient(circle,rgba(0,146,214,.04) 1px,transparent 1px)',backgroundSize:'28px 28px',WebkitMaskImage:'radial-gradient(ellipse 55% 50% at 50% 50%,white,transparent)',maskImage:'radial-gradient(ellipse 55% 50% at 50% 50%,white,transparent)',animation:'dotGrid 8s ease-in-out infinite'}} />
      <div style={{position:'absolute',inset:0,overflow:'hidden',pointerEvents:'none'}}>
        <div style={{position:'absolute',width:400,height:400,top:'-10%',right:'-6%',background:'linear-gradient(135deg,rgba(0,146,214,.16),rgba(0,200,180,.07))',filter:'blur(65px)',animation:'orbDrift 20s ease-in-out infinite'}} />
        <div style={{position:'absolute',width:360,height:360,bottom:'-6%',left:'-8%',background:'linear-gradient(135deg,rgba(90,46,145,.14),rgba(139,92,246,.06))',filter:'blur(65px)',animation:'orbDrift 26s ease-in-out infinite reverse'}} />
      </div>
      <div style={{position:'absolute',inset:0,overflow:'hidden',pointerEvents:'none'}}>
        {stars.map((s, i) => <div key={i} style={{position:'absolute',width:s.size,height:s.size,left:s.x,top:s.y,borderRadius:'50%',background:s.color,animation:`twinkle ${s.dur} ease-in-out ${s.delay} infinite`}} />)}
      </div>
      <div style={{position:'absolute',inset:0,overflow:'hidden',pointerEvents:'none'}}>
        {FLOATING_ELEMENTS.map((el, i) => (
          <span key={i} style={{position:'absolute',left:el.x,top:el.y,fontSize:el.size,fontWeight:700,fontFamily:'monospace',color:el.color,animation:`floatBracket ${el.dur} ease-in-out ${el.delay} infinite`,userSelect:'none'}}>{el.text}</span>
        ))}
      </div>
      <div style={{position:'relative',zIndex:10,width:'100%',display:'flex',flexDirection:'column',alignItems:'center',justifyContent:'center',padding:'0 16px',animation:'blurIn .5s cubic-bezier(.22,1,.36,1) both'}}>
        {children}
      </div>
    </div>
  )
}

export default function App() {
  const [step, setStep] = useState<DesignStep>(null)
  // Detect editor-iframe vs deployed-standalone. The loader UI is only meaningful
  // in the editor preview (where the iframe genuinely waits for postMessage from
  // the parent). On a deployed standalone URL there is no parent and nothing to
  // load — so we render nothing rather than a loader that never resolves.
  const isInEditor = typeof window !== 'undefined' && window.parent !== window

  useEffect(() => {
    function onMessage(ev: MessageEvent) {
      if (ev.data?.type === 'design-step') setStep(ev.data.step ?? null)
    }
    window.addEventListener('message', onMessage)
    window.parent?.postMessage({ type: 'preview-ready' }, '*')
    return () => window.removeEventListener('message', onMessage)
  }, [])

  if (!isInEditor) return null

  return (
    <>
      <style>{GLOBAL_STYLES}</style>
      {step === 'logo' ? <LogoScreen /> : step === 'theme' ? <ThemeScreen /> : step === 'reference' ? <ReferenceScreen /> : <WaitingScreen />}
    </>
  )
}

